function updateItemRoute(req,res){try{const body=req.body||{}; const {name,cost,category,active,sku,notes}=body; const item=db.prepare('SELECT * FROM items WHERE id=?').get(req.params.id); if(!item) return res.status(404).json({error:'Item not found'}); const nextStock='stock_qty' in body?parseStock(body.stock_qty):item.stock_qty; db.prepare('UPDATE items SET name=?,cost_cents=?,category=?,active=?,sku=?,notes=?,stock_qty=?,updated_at=? WHERE id=?').run(String(name||'').trim(),cents(cost),String(category||'').trim(),active?1:0,String(sku||''),String(notes||''),nextStock,now(),req.params.id); res.json({ok:true})}catch(e){res.status(400).json({error:e.message})}}
