app.get('/api/stock',requirePermission('page.stock'),(req,res)=>res.json({items:db.prepare(`SELECT i.*, (SELECT max(created_at) FROM stock_adjustments sa WHERE sa.item_id=i.id) last_stock_update FROM items i ORDER BY active DESC, category,name`).all(),recent:db.prepare(`SELECT sa.*,i.name item_name,u.display_name user_display_name FROM stock_adjustments sa JOIN items i ON i.id=sa.item_id LEFT JOIN users u ON u.id=sa.user_id ORDER BY sa.created_at DESC LIMIT 25`).all()}));
app.post('/api/stock/:itemId/add',requirePermission('page.stock'),(req,res)=>{try{const itemId=String(req.params.itemId||''); const raw=req.body?.quantity; if(!/^\d+$/.test(String(raw))) return res.status(400).json({error:'Quantity must be a positive whole number'}); const q=Number(raw); if(!Number.isSafeInteger(q)||q<=0) return res.status(400).json({error:'Quantity must be greater than zero'}); const item=db.prepare('SELECT * FROM items WHERE id=?').get(itemId); if(!item) return res.status(404).json({error:'Item not found'}); const stamp=now(), id='stock_'+nanoid(); let updated; const run=db.transaction(()=>{db.prepare('UPDATE items SET stock_qty=COALESCE(stock_qty,0)+?,updated_at=? WHERE id=?').run(q,stamp,itemId); updated=db.prepare('SELECT stock_qty FROM items WHERE id=?').get(itemId).stock_qty; db.prepare('INSERT INTO stock_adjustments(id,item_id,quantity_change,resulting_quantity,adjustment_type,reason,user_id,created_at) VALUES(?,?,?,?,?,?,?,?)').run(id,itemId,q,updated,'manual_add','Manual stock addition',req.user.id,stamp)}); run(); res.json({ok:true,itemId,quantityAdded:q,stock_qty:updated})}catch(e){res.status(500).json({error:e.message})}});
app.post('/api/items/:id/stock',requireRole('ADMIN','OWNER'),(req,res)=>{try{const {action,qty}=req.body||{}; const item=db.prepare('SELECT * FROM items WHERE id=?').get(req.params.id); if(!item) return res.status(404).json({error:'Item not found'}); let next; if(action==='untrack') next=null; else{const n=Math.round(Number(qty)); if(Number.isNaN(n)) throw Error('Quantity must be a number'); if(action==='set') next=n; else if(action==='add') next=(item.stock_qty||0)+n; else if(action==='subtract') next=(item.stock_qty||0)-n; else throw Error('Invalid stock action')} db.prepare('UPDATE items SET stock_qty=?,updated_at=? WHERE id=?').run(next,now(),req.params.id); event('stock_adjust','ok',`${item.name}: ${action} ${action==='untrack'?'':qty} → ${next==null?'untracked':next}`); res.json({ok:true,stock_qty:next})}catch(e){res.status(400).json({error:e.message})}});
app.get('/api/campers',requirePermission('page.people'),(req,res)=>res.json(db.prepare('SELECT * FROM campers ORDER BY name').all()));
app.post('/api/campers',requirePermission('page.people'),(req,res)=>{try{const {name,type,person_type,cabin,initial_balance,current_balance,active,notes}=req.body||{}; const trimmed=String(name||'').trim(); if(!trimmed) throw Error('Name is required'); const initial=cents(initial_balance); const current=cents(current_balance); const stamp=now(), id='manual_'+nanoid(); const ptype=validatePersonType(person_type||type); const enabled=active===false?0:1; const run=db.transaction(()=>{db.prepare('INSERT INTO campers(id,name,person_type,initial_balance_cents,current_balance_cents,sheet_row,active,notes,source,cabin,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?)').run(id,trimmed,ptype,initial,current,null,enabled,String(notes||''),'manual',String(cabin||'').trim()||null,stamp); const auditId='audit_'+nanoid(); db.prepare('INSERT INTO audit_logs(id,created_at,admin,action,person_id,person_name,initial_balance_cents,current_balance_cents,details_json) VALUES(?,?,?,?,?,?,?,?,?)').run(auditId,stamp,req.user.displayName,'manual_person_create',id,trimmed,initial,current,JSON.stringify({type:ptype,active:!!enabled,notes:String(notes||'')})); recordOpeningLedger(db,{camperId:id,balanceCents:current,auditLogId:auditId,user:req.user,createdAt:stamp,metadata:{source:'manual_person_create'}})}); run(); res.json({ok:true,id})}catch(e){res.status(400).json({error:e.message})}});
app.get('/api/audit-logs',requireRole('ADMIN','OWNER'),(req,res)=>res.json(db.prepare('SELECT * FROM audit_logs ORDER BY created_at DESC LIMIT 200').all()));
function updateCamperRoute(req,res){try{const body=req.body||{}; const {name,type,person_type,cabin,initial_balance,current_balance,active,notes}=body; const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Person not found'}); if(current_balance!==undefined&&current_balance!==''&&cents(current_balance)!==camper.current_balance_cents) return res.status(400).json({error:'Balance changes must use the adjustment endpoint.'}); if(body.expected_updated_at && camper.updated_at && String(body.expected_updated_at)!==String(camper.updated_at)) return res.status(409).json({error:'This camper was just changed on another device. The list has been refreshed — re-apply your edit.',conflict:true}); const nextName=String(name||'').trim(); if(!nextName) throw Error('Name is required'); const nextInitial=initial_balance!==undefined&&initial_balance!==''?cents(initial_balance):camper.initial_balance_cents; /* TODO Phase 3: make opening balance read-only after creation/import. */ const nextCabin='cabin' in body?(String(cabin||'').trim()||null):camper.cabin; db.prepare('UPDATE campers SET name=?,person_type=?,cabin=?,initial_balance_cents=?,active=?,notes=?,updated_at=? WHERE id=?').run(nextName,validatePersonType(person_type||type||camper.person_type),nextCabin,nextInitial,active?1:0,String(notes||''),now(),req.params.id); res.json({ok:true})}catch(e){res.status(400).json({error:e.message})}}
// Day-of registration: any signed-in user (clerks included) can add a walk-up camper. Registered before :id so it is not shadowed.
app.post('/api/campers/quick-add',(req,res)=>{try{const {name,cabin,person_type,type}=req.body||{}; const trimmed=String(name||'').trim(); if(!trimmed) throw Error('Name is required'); const rawBal=req.body?.initial_balance ?? req.body?.balance ?? req.body?.current_balance ?? 0; const bal=cents(rawBal===''?0:rawBal); const ptype=validatePersonType(person_type||type); const stamp=now(), id='walkin_'+nanoid(); const run=db.transaction(()=>{db.prepare('INSERT INTO campers(id,name,person_type,initial_balance_cents,current_balance_cents,sheet_row,active,notes,source,cabin,updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?)').run(id,trimmed,ptype,bal,bal,null,1,'','manual',String(cabin||'').trim()||null,stamp); const auditId='audit_'+nanoid(); db.prepare('INSERT INTO audit_logs(id,created_at,admin,action,person_id,person_name,initial_balance_cents,current_balance_cents,details_json) VALUES(?,?,?,?,?,?,?,?,?)').run(auditId,stamp,req.user.displayName,'walkin_person_create',id,trimmed,bal,bal,JSON.stringify({cabin:String(cabin||'').trim()||null,type:ptype})); recordOpeningLedger(db,{camperId:id,balanceCents:bal,auditLogId:auditId,user:req.user,createdAt:stamp,metadata:{source:'walkin_person_create'}})}); run(); event('walkin_add','ok',`${req.user.displayName} registered ${trimmed}${cabin?` (${String(cabin).trim()})`:''} with ${money(bal)}`); res.json({ok:true,camper:db.prepare('SELECT * FROM campers WHERE id=?').get(id)})}catch(e){res.status(400).json({error:e.message})}});

app.get('/api/campers/:id/history',requirePermission('page.people'),(req,res)=>{try{const camper=db.prepare('SELECT id,name,person_type,cabin,initial_balance_cents,current_balance_cents,active FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Camper not found'}); const requestedLimit=Number.parseInt(String(req.query.limit??'50'),10); const requestedOffset=Number.parseInt(String(req.query.offset??'0'),10); const limit=Math.min(100,Math.max(1,Number.isFinite(requestedLimit)?requestedLimit:50)); const offset=Math.max(0,Number.isFinite(requestedOffset)?requestedOffset:0); const total=db.prepare('SELECT count(*) c FROM account_ledger WHERE camper_id=?').get(camper.id).c; const rows=db.prepare(`SELECT l.*,t.id tx_id,t.camper_id tx_camper_id,t.total_cents tx_total_cents,t.items_json tx_items_json,a.id adj_id,a.camper_id adj_camper_id,a.action adj_action,a.reason adj_reason,a.admin adj_admin,a.amount_cents adj_amount_cents,a.previous_balance_cents adj_previous_balance_cents,a.new_balance_cents adj_new_balance_cents FROM account_ledger l LEFT JOIN transactions t ON t.id=l.transaction_id AND t.camper_id=l.camper_id LEFT JOIN balance_adjustments a ON a.id=l.balance_adjustment_id AND a.camper_id=l.camper_id WHERE l.camper_id=? ORDER BY l.created_at DESC,l.id DESC LIMIT ? OFFSET ?`).all(camper.id,limit,offset); res.json({camper,entries:rows.map(buildHistoryEntry),pagination:{limit,offset,total,has_more:offset+rows.length<total}})}catch(e){res.status(500).json({error:e.message})}});
app.put('/api/campers/:id',requireRole('ADMIN','OWNER'),updateCamperRoute);
app.post('/api/campers/:id',requireRole('ADMIN','OWNER'),updateCamperRoute);
app.post('/api/campers/:id/adjust',requireRole('ADMIN','OWNER'),(req,res)=>{try{const {action,amount,reason}=req.body||{}; if(!String(reason||'').trim()) throw Error('Reason is required'); const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Camper not found'}); let amt=action==='set'?null:cents(amount); let next=action==='add'?camper.current_balance_cents+amt:action==='subtract'?camper.current_balance_cents-amt:action==='set'?cents(amount):null; if(next===null) throw Error('Invalid adjustment action'); const id='adj_'+nanoid(), stamp=now(); const entryType=action==='add'?'funds_added':action==='subtract'?'funds_subtracted':'balance_set'; const run=db.transaction(()=>{db.prepare('INSERT INTO balance_adjustments(id,created_at,admin,camper_id,camper_name,action,amount_cents,previous_balance_cents,new_balance_cents,reason) VALUES(?,?,?,?,?,?,?,?,?,?)').run(id,stamp,req.user.displayName,camper.id,camper.name,action,amt,camper.current_balance_cents,next,String(reason).trim()); applyBalanceChange(db,{camperId:camper.id,entryType,setBalanceCents:next,balanceAdjustmentId:id,reason:String(reason).trim(),user:req.user,createdAt:stamp,metadata:{source:'manual_adjustment',action}})}); run(); res.json({ok:true,id,new_balance_cents:next})}catch(e){res.status(400).json({error:e.message})}});
app.get('/api/balance-adjustments',requireRole('ADMIN','OWNER'),(req,res)=>res.json(db.prepare('SELECT * FROM balance_adjustments ORDER BY created_at DESC LIMIT 200').all()));
// Day-of registration: any signed-in user (clerks included) can move campers between cabins.
app.post('/api/campers/:id/cabin',(req,res)=>{try{const camper=db.prepare('SELECT * FROM campers WHERE id=?').get(req.params.id); if(!camper) return res.status(404).json({error:'Camper not found'}); const nextCabin=String(req.body?.cabin||'').trim()||null; const stamp=now(); const run=db.transaction(()=>{db.prepare('UPDATE campers SET cabin=?,updated_at=? WHERE id=?').run(nextCabin,stamp,camper.id); db.prepare('INSERT INTO audit_logs(id,created_at,admin,action,person_id,person_name,initial_balance_cents,current_balance_cents,details_json) VALUES(?,?,?,?,?,?,?,?,?)').run('audit_'+nanoid(),stamp,req.user.displayName,'cabin_move',camper.id,camper.name,camper.initial_balance_cents,camper.current_balance_cents,JSON.stringify({from:camper.cabin||null,to:nextCabin}))}); run(); res.json({ok:true,cabin:nextCabin,updated_at:stamp})}catch(e){res.status(400).json({error:e.message})}});
app.get('/api/cabins',(req,res)=>res.json(db.prepare("SELECT COALESCE(NULLIF(TRIM(cabin),''),'') cabin, count(*) c, COALESCE(SUM(current_balance_cents),0) balance FROM campers WHERE active=1 GROUP BY cabin ORDER BY cabin='', cabin").all().map(r=>({cabin:r.cabin||null,count:r.c,balance_cents:r.balance}))));

