app.post('/api/sale',(req,res)=>{try{const {camperId, cart, allowOverride}=req.body; const camper=db.prepare('SELECT * FROM campers WHERE id=? AND active=1').get(camperId); if(!camper) return res.status(404).json({error:'Camper not found'}); if(!Array.isArray(cart)||!cart.length) return res.status(400).json({error:'Cart is empty'}); const items=cart.map(ci=>{const item=db.prepare('SELECT * FROM items WHERE id=? AND active=1').get(ci.id); if(!item) throw Error('Item not found'); const qty=Math.max(1,Number(ci.qty)||1); return {id:item.id,name:item.name,price_cents:item.cost_cents,qty,line_total_cents:item.cost_cents*qty}}); const total=items.reduce((a,i)=>a+i.line_total_cents,0); const allow=db.prepare("SELECT value FROM settings WHERE key='allow_over_balance'").get()?.value==='true'; if(camper.current_balance_cents-total<0 && !allow && !allowOverride) return res.status(409).json({error:'Purchase exceeds current balance'}); const txid='tx_'+nanoid(); const created=now(); const run=db.transaction(()=>{db.prepare('INSERT INTO transactions(id,created_at,clerk,camper_id,camper_name,previous_balance_cents,total_cents,new_balance_cents,items_json) VALUES(?,?,?,?,?,?,?,?,?)').run(txid,created,req.user.displayName,camper.id,camper.name,camper.current_balance_cents,total,camper.current_balance_cents-total,JSON.stringify(items)); applyBalanceChange(db,{camperId:camper.id,entryType:'purchase',deltaCents:-total,transactionId:txid,user:req.user,createdAt:created,metadata:{source:'sale',item_count:items.length,total_cents:total}}); for(const it of items){db.prepare('UPDATE items SET stock_qty=stock_qty-? WHERE id=? AND stock_qty IS NOT NULL').run(it.qty,it.id)}}); run(); res.json({ok:true,id:txid,camperId:camper.id,new_balance_cents:camper.current_balance_cents-total})}catch(e){res.status(400).json({error:e.message})}});

