app.post('/api/settings/google',requireRole('ADMIN','OWNER'),(req,res)=>{try{let {sheetUrl,spreadsheetId,campersSheetName,logsSheetName,serviceAccountEmail,privateKey,serviceAccountJson}=req.body||{}; if(serviceAccountJson){const parsed=typeof serviceAccountJson==='string'?JSON.parse(serviceAccountJson):serviceAccountJson; spreadsheetId=spreadsheetId||parsed.spreadsheet_id||parsed.spreadsheetId; serviceAccountEmail=serviceAccountEmail||parsed.client_email; privateKey=privateKey||parsed.private_key} sheetUrl=String(sheetUrl||spreadsheetId||'').trim(); spreadsheetId=extractSpreadsheetId(spreadsheetId||sheetUrl); campersSheetName=String(campersSheetName||DEFAULT_SHEETS.campers).trim(); logsSheetName=String(logsSheetName||DEFAULT_SHEETS.logs).trim(); serviceAccountEmail=String(serviceAccountEmail||'').trim(); privateKey=String(privateKey||'').trim(); if(!spreadsheetId) return res.status(400).json({error:'Missing Google Sheet URL or spreadsheet ID'}); if(!campersSheetName||!logsSheetName) return res.status(400).json({error:'Missing one or more tab names'}); if(!serviceAccountEmail) return res.status(400).json({error:'Missing service account email'}); if(!privateKey && !getSetting('google_private_key') && !process.env.GOOGLE_PRIVATE_KEY) return res.status(400).json({error:'Missing private key'}); saveSetting('google_sheet_url',sheetUrl); saveSetting('google_spreadsheet_id',spreadsheetId); saveSetting('google_campers_sheet_name',campersSheetName); saveSetting('google_logs_sheet_name',logsSheetName); saveSetting('google_service_account_email',serviceAccountEmail); if(privateKey) saveSetting('google_private_key',privateKey); res.json({ok:true,google:googleStatus()})}catch(e){res.status(400).json({error:'Invalid service account JSON or settings: '+e.message})}});
